const item = $input.first();
const body = item.json.body;
const crypto = require('crypto');
const gigachatAuth = 'Basic ' + Buffer.from($env.GIGACHAT_CLIENT_ID + ':' + $env.GIGACHAT_CLIENT_SECRET).toString('base64');
const rquid = crypto.randomUUID();
return [{ json: { org_id: body.org_id, user_max_id: body.user_max_id, work_types: body.work_types, parameters: body.parameters, _gigachat_auth: gigachatAuth, _rquid: rquid } }];

const authResult = $input.first().json;
const inputData = $('Parse Input').first().json;
return [{ json: { ...inputData, access_token: authResult.access_token } }];

// Читаем справочник рецептов из Google Sheets
// TODO: Заменить SPREADSHEET_ID на реальный ID таблицы с рецептами
// Формат таблицы: Вид работы | Материал | Единица | Норма на м² | Цена материала | Цена работы за м²
const https = require('https');
const prevData = $input.first().json;

// Для MVP: формируем запрос к GigaChat с описанием видов работ
// В продакшене здесь будет Google Sheets API для чтения рецептов
const workTypesText = prevData.work_types.join(', ');
const params = prevData.parameters;

return [{ json: { ...prevData, work_types_text: workTypesText, room_area: params.roomArea || 0, room_height: params.roomHeight || 2.7, room_count: params.roomCount || 1, additional_notes: params.additionalNotes || '' } }];

const chatResult = $input.first().json;
const prevData = $('Prepare Estimate Data').first().json;
const content = chatResult.choices[0].message.content;

// Парсим JSON из ответа GigaChat
let estimateData;
try {
  // Пробуем найти JSON в ответе
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    estimateData = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('JSON not found in response');
  }
} catch (e) {
  // Фолбэк: создаём простую структуру
  estimateData = {
    items: prevData.work_types.map(wt => ({
      work_type: wt,
      materials: [{ name: 'Материалы (уточнить)', unit: 'комплект', quantity: 1, price: 0 }],
      labor_cost: 0,
      total_cost: 0
    })),
    total_cost: 0
  };
}

const title = prevData.work_types.slice(0, 3).join(', ') + (prevData.work_types.length > 3 ? '...' : '');

return [{ json: { org_id: prevData.org_id, user_max_id: prevData.user_max_id, title, parameters: prevData.parameters, items: estimateData.items || [], total_cost: estimateData.total_cost || 0, result_data: estimateData } }];

const { Client } = require('pg');
const item = $input.first().json;
const client = new Client({ host: $env.APP_PG_HOST || 'db', port: parseInt($env.APP_PG_PORT || '5432'), user: $env.APP_PG_USER, password: $env.APP_PG_PASSWORD, database: ($env.APP_PG_DATABASE || 'ragkb_app') });
await client.connect();
try {
  // Insert Estimate
  const estResult = await client.query(
    'INSERT INTO "Estimate" (organization_id, title, parameters, status, total_cost, result_data, created_at, updated_at) VALUES ($1, $2, $3, $4, $5, $6, NOW(), NOW()) RETURNING id',
    [item.org_id, item.title, JSON.stringify(item.parameters), 'ready', item.total_cost, JSON.stringify(item.result_data)]
  );
  const estimateId = estResult.rows[0].id;

  // Insert EstimateItems
  for (const ei of item.items) {
    await client.query(
      'INSERT INTO "EstimateItem" (estimate_id, work_type, materials, labor_cost, total_cost) VALUES ($1, $2, $3, $4, $5)',
      [estimateId, ei.work_type, JSON.stringify(ei.materials), ei.labor_cost || 0, ei.total_cost || 0]
    );
  }

  return [{ json: { estimate_id: estimateId, items: item.items, total_cost: item.total_cost } }];
} finally {
  await client.end();
}
